import{_ as a,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse(`{"title":"DM Pairing and Access Control: Protect Your AI Assistant | Clawdbot Tutorial","description":"Learn Clawdbot's DM pairing protection mechanism, including approving pairing requests from unknown senders via CLI, listing pending requests, and managing allowlists. This tutorial covers the complete pairing workflow, CLI command usage, access policy configuration, and security best practices, with troubleshooting and doctor command.","frontmatter":{"title":"DM Pairing and Access Control: Protect Your AI Assistant | Clawdbot Tutorial","sidebarTitle":"DM Pairing and Access Control","subtitle":"DM Pairing and Access Control: Protect Your AI Assistant","description":"Learn Clawdbot's DM pairing protection mechanism, including approving pairing requests from unknown senders via CLI, listing pending requests, and managing allowlists. This tutorial covers the complete pairing workflow, CLI command usage, access policy configuration, and security best practices, with troubleshooting and doctor command.","tags":["getting-started","security","pairing","access-control"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"moltbot/moltbot/start/pairing-approval/index.md","filePath":"moltbot/moltbot/start/pairing-approval/index.md"}`),n={name:"moltbot/moltbot/start/pairing-approval/index.md"};function o(r,e,l,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="dm-pairing-and-access-control-protect-your-ai-assistant" tabindex="-1">DM Pairing and Access Control: Protect Your AI Assistant <a class="header-anchor" href="#dm-pairing-and-access-control-protect-your-ai-assistant" aria-label="Permalink to &quot;DM Pairing and Access Control: Protect Your AI Assistant&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>After completing this tutorial, you will be able to:</p><ul><li>✅ Understand the default DM pairing protection mechanism</li><li>✅ Approve pairing requests from unknown senders</li><li>✅ List and manage pending pairing requests</li><li>✅ Configure different DM access policies (pairing/allowlist/open)</li><li>✅ Run doctor checks for security configuration</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>You may have just configured a WhatsApp or Telegram channel and want to chat with your AI assistant, but are encountering these issues:</p><ul><li>&quot;Why doesn&#39;t Clawdbot reply when strangers send me messages?&quot;</li><li>&quot;Received a pairing code, but I don&#39;t know what it means&quot;</li><li>&quot;Want to approve someone&#39;s request but don&#39;t know which command to use&quot;</li><li>&quot;How can I check who is currently waiting for approval?&quot;</li></ul><p>The good news is: <strong>Clawdbot enables DM pairing protection by default</strong>, ensuring that only senders you authorize can chat with your AI assistant.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p>When you need to:</p><ul><li>🛡 <strong>Protect privacy</strong>: Ensure only trusted users can chat with your AI assistant</li><li>✅ <strong>Approve strangers</strong>: Allow new senders to access your AI assistant</li><li>🔒 <strong>Strict access control</strong>: Limit access for specific users</li><li>📋 <strong>Batch management</strong>: View and manage all pending pairing requests</li></ul><hr><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><h3 id="what-is-dm-pairing" tabindex="-1">What is DM Pairing? <a class="header-anchor" href="#what-is-dm-pairing" aria-label="Permalink to &quot;What is DM Pairing?&quot;">​</a></h3><p>Clawdbot connects to real messaging platforms (WhatsApp, Telegram, Slack, etc.), and <strong>direct messages (DMs) on these platforms are treated as untrusted input by default</strong>.</p><p>To protect your AI assistant, Clawdbot provides a <strong>pairing mechanism</strong>:</p><div class="info custom-block"><p class="custom-block-title">Pairing Flow</p><ol><li>Unknown sender sends you a message</li><li>Clawdbot detects the sender is unauthorized</li><li>Clawdbot returns a <strong>pairing code</strong> (8 characters)</li><li>The sender needs to provide the pairing code to you</li><li>You approve the code via CLI</li><li>Sender ID is added to the allowlist</li><li>The sender can now chat normally with the AI assistant</li></ol></div><h3 id="default-dm-policy" tabindex="-1">Default DM Policy <a class="header-anchor" href="#default-dm-policy" aria-label="Permalink to &quot;Default DM Policy&quot;">​</a></h3><p><strong>All channels use <code>dmPolicy=&quot;pairing&quot;</code> by default</strong>, which means:</p><table tabindex="0"><thead><tr><th>Policy</th><th>Behavior</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>Unknown senders receive a pairing code, message is not processed (default)</td></tr><tr><td><code>allowlist</code></td><td>Only allow senders in the <code>allowFrom</code> list</td></tr><tr><td><code>open</code></td><td>Allow all senders (requires explicit configuration <code>&quot;*&quot;</code>)</td></tr><tr><td><code>disabled</code></td><td>Completely disable DM functionality</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Security Reminder</p><p>The default <code>pairing</code> mode is the safest choice. Unless you have special requirements, do not change to <code>open</code> mode.</p></div><hr><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><p>Ensure you have already:</p><ul><li>[x] Completed the <a href="./../getting-started/">Quick Start</a> tutorial</li><li>[x] Completed the <a href="./../gateway-startup/">Starting Gateway</a> tutorial</li><li>[x] Configured at least one messaging channel (WhatsApp, Telegram, Slack, etc.)</li><li>[x] Gateway is running</li></ul><hr><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-understand-the-source-of-pairing-codes" tabindex="-1">Step 1: Understand the Source of Pairing Codes <a class="header-anchor" href="#step-1-understand-the-source-of-pairing-codes" aria-label="Permalink to &quot;Step 1: Understand the Source of Pairing Codes&quot;">​</a></h3><p>When an unknown sender sends a message to your Clawdbot, they receive a reply similar to this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>Key features of pairing codes</strong> (source: <code>src/pairing/pairing-store.ts</code>):</p><ul><li><strong>8 characters</strong>: Easy to input and remember</li><li><strong>Uppercase letters and numbers</strong>: Avoid confusion</li><li><strong>Excludes confusing characters</strong>: No 0, O, 1, I</li><li><strong>1 hour validity</strong>: Automatically expires after time</li><li><strong>Maximum 3 pending requests</strong>: Automatically removes oldest request when exceeded</li></ul><h3 id="step-2-list-pending-pairing-requests" tabindex="-1">Step 2: List Pending Pairing Requests <a class="header-anchor" href="#step-2-list-pending-pairing-requests" aria-label="Permalink to &quot;Step 2: List Pending Pairing Requests&quot;">​</a></h3><p>Run the following command in your terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>If there are no pending requests, you will see:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Supported Channels</p><p>Pairing functionality supports the following channels:</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="step-3-approve-a-pairing-request" tabindex="-1">Step 3: Approve a Pairing Request <a class="header-anchor" href="#step-3-approve-a-pairing-request" aria-label="Permalink to &quot;Step 3: Approve a Pairing Request&quot;">​</a></h3><p>Use the pairing code provided by the sender to approve access:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Effect After Approval</p><p>After approval, the sender ID (123456789) is automatically added to the allowlist for that channel, stored in: <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="step-4-notify-the-sender-optional" tabindex="-1">Step 4: Notify the Sender (Optional) <a class="header-anchor" href="#step-4-notify-the-sender-optional" aria-label="Permalink to &quot;Step 4: Notify the Sender (Optional)&quot;">​</a></h3><p>If you want to automatically notify the sender, you can use the <code>--notify</code> flag:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>The sender will receive the following message (source: <code>src/channels/plugins/pairing-message.ts</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>Note</strong>: The <code>--notify</code> flag requires Clawdbot Gateway to be running and the channel to be active.</p><h3 id="step-5-verify-the-sender-can-chat-normally" tabindex="-1">Step 5: Verify the Sender Can Chat Normally <a class="header-anchor" href="#step-5-verify-the-sender-can-chat-normally" aria-label="Permalink to &quot;Step 5: Verify the Sender Can Chat Normally&quot;">​</a></h3><p>Ask the sender to send another message, and the AI assistant should respond normally.</p><hr><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>Complete the following checks to confirm correct configuration:</p><ul><li>[ ] Running <code>clawdbot pairing list &lt;channel&gt;</code> shows pending requests</li><li>[ ] Using <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> successfully approves</li><li>[ ] Approved senders can chat normally with the AI assistant</li><li>[ ] Pairing codes automatically expire after 1 hour (verify by sending another message)</li></ul><hr><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="error-1-pairing-code-not-found" tabindex="-1">Error 1: Pairing Code Not Found <a class="header-anchor" href="#error-1-pairing-code-not-found" aria-label="Permalink to &quot;Error 1: Pairing Code Not Found&quot;">​</a></h3><p><strong>Error message</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>Possible causes</strong>:</p><ul><li>Pairing code has expired (over 1 hour)</li><li>Pairing code was entered incorrectly (check case sensitivity)</li><li>Sender didn&#39;t actually send a message (pairing code is only generated when a message is received)</li></ul><p><strong>Solution</strong>:</p><ul><li>Ask the sender to send another message to generate a new pairing code</li><li>Ensure the pairing code is copied correctly (note case sensitivity)</li></ul><h3 id="error-2-channel-does-not-support-pairing" tabindex="-1">Error 2: Channel Does Not Support Pairing <a class="header-anchor" href="#error-2-channel-does-not-support-pairing" aria-label="Permalink to &quot;Error 2: Channel Does Not Support Pairing&quot;">​</a></h3><p><strong>Error message</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>Possible causes</strong>:</p><ul><li>Channel name spelling error</li><li>The channel does not support pairing functionality</li></ul><p><strong>Solution</strong>:</p><ul><li>Run <code>clawdbot pairing list</code> to see the list of supported channels</li><li>Use the correct channel name</li></ul><h3 id="error-3-notification-failed" tabindex="-1">Error 3: Notification Failed <a class="header-anchor" href="#error-3-notification-failed" aria-label="Permalink to &quot;Error 3: Notification Failed&quot;">​</a></h3><p><strong>Error message</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>Possible causes</strong>:</p><ul><li>Gateway is not running</li><li>Channel connection is lost</li><li>Network issues</li></ul><p><strong>Solution</strong>:</p><ul><li>Confirm Gateway is running</li><li>Check channel connection status: <code>clawdbot channels status</code></li><li>Don&#39;t use the <code>--notify</code> flag and manually notify the sender</li></ul><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>This tutorial introduced Clawdbot&#39;s DM pairing protection mechanism:</p><ul><li><strong>Default security</strong>: All channels use <code>pairing</code> mode by default to protect your AI assistant</li><li><strong>Pairing workflow</strong>: Unknown senders receive an 8-character pairing code, and you need to approve it via CLI</li><li><strong>Management commands</strong>: <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>: List pending requests</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>: Approve pairing</li></ul></li><li><strong>Storage location</strong>: Allowlist is stored in <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code></li><li><strong>Auto-expiry</strong>: Pairing requests automatically expire after 1 hour</li></ul><p>Remember: <strong>The pairing mechanism is the security foundation of Clawdbot</strong>, ensuring only people you authorize can chat with your AI assistant.</p><hr><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we will learn <strong><a href="./../../faq/troubleshooting/">Troubleshooting: Common Issues</a></strong>.</p><p>You will learn:</p><ul><li>Quick diagnosis and system status checks</li><li>Resolving Gateway startup, channel connection, authentication errors, and other issues</li><li>Troubleshooting methods for tool call failures and performance optimization</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Pairing code generation (8 characters, excludes confusing characters)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>Pairing request storage and TTL (1 hour)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>Approve pairing command</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>Pairing code message generation</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>Allowlist storage</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td>List of channels supporting <code>pairing</code></td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>Default DM policy (pairing)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>Key constants</strong>:</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>: Pairing code length</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>: Pairing code character set (excludes 0O1I)</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>: Pairing request validity period (1 hour)</li><li><code>PAIRING_PENDING_MAX = 3</code>: Maximum pending requests</li></ul><p><strong>Key functions</strong>:</p><ul><li><code>approveChannelPairingCode()</code>: Approve pairing code and add to allowlist</li><li><code>listChannelPairingRequests()</code>: List pending pairing requests</li><li><code>upsertChannelPairingRequest()</code>: Create or update pairing request</li><li><code>addChannelAllowFromStoreEntry()</code>: Add sender to allowlist</li></ul></details>`,92)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
